import { DEMO_MODE, DEMO_AGENCY_ID } from '@/lib/config';
import { apiClient } from '@/lib/api/client';
import {
  mockBranches, mockDeliverers, mockVehicles, mockHubs, mockMissions, mockCommissions,
} from '@/lib/mock-data';

export interface AgencyDashboard {
  agencyId: string;
  branchesCount: number;
  deliverersCount: number;
  hubsCount: number;
  vehiclesCount: number;
  activeMissionsCount: number;
  pendingCommissionsCount: number;
}

export interface AgencyReport {
  agencyId: string;
  missionsByStatus: Record<string, number>;
  commissionsByStatus: Record<string, number>;
}

function demoDashboard(agencyId: string): AgencyDashboard {
  const active = mockMissions.filter(m =>
    ['PENDING', 'ASSIGNED', 'IN_TRANSIT'].includes(m.status),
  ).length;
  const pendingComm = mockCommissions.filter(c => c.status === 'CALCULATED').length;
  return {
    agencyId,
    branchesCount: mockBranches.length,
    deliverersCount: mockDeliverers.length,
    hubsCount: mockHubs.length,
    vehiclesCount: mockVehicles.length,
    activeMissionsCount: active,
    pendingCommissionsCount: pendingComm,
  };
}

export const analyticsService = {
  async getDashboard(agencyId = DEMO_AGENCY_ID): Promise<AgencyDashboard> {
    if (DEMO_MODE) return demoDashboard(agencyId);
    return apiClient.get<AgencyDashboard>(`/agencies/${agencyId}/dashboard`);
  },

  async getReports(agencyId = DEMO_AGENCY_ID): Promise<AgencyReport> {
    if (DEMO_MODE) {
      const missionsByStatus: Record<string, number> = {};
      for (const m of mockMissions) {
        missionsByStatus[m.status] = (missionsByStatus[m.status] ?? 0) + 1;
      }
      const commissionsByStatus: Record<string, number> = {};
      for (const c of mockCommissions) {
        commissionsByStatus[c.status] = (commissionsByStatus[c.status] ?? 0) + 1;
      }
      return { agencyId, missionsByStatus, commissionsByStatus };
    }
    return apiClient.get<AgencyReport>(`/agencies/${agencyId}/reports`);
  },
};
