import { DEMO_MODE, DEMO_AGENCY_ID } from '@/lib/config';
import { apiClient } from '@/lib/api/client';
import { mapAgency } from '@/lib/api/mappers';
import { mockAgency } from '@/lib/mock-data';
import type { Agency } from '@/lib/types';
import type { AgencyDto } from '@/lib/api/dto';

export const agencyService = {
  async getAgency(id = DEMO_AGENCY_ID): Promise<Agency> {
    if (DEMO_MODE) return mockAgency;
    const dto = await apiClient.get<AgencyDto>(`/agencies/${id}`);
    return mapAgency(dto);
  },

  async activateAgency(id: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.patch(`/agencies/${id}/activate`, {});
  },

  async suspendAgency(id: string, reason: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.patch(
      `/agencies/${id}/suspend?reason=${encodeURIComponent(reason)}`,
      {},
    );
  },

  async updateSettings(id: string, settings: Partial<Agency>): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.patch(`/agencies/${id}/settings`, {
      autoAssignMissions: settings.autoAssignMissions,
      allowFreelancerAssociation: settings.allowFreelancerAssociation,
      hubRetentionDelayHours: settings.hubRetentionDelayHours,
      defaultCommissionRate: undefined,
      maxActiveBranches: undefined,
      timezone: 'Africa/Douala',
    });
  },
};
